          "Bash(pkill -:*)"
          "Bash(nc -l -:*)"
          "Bash(ncat -l -:*)"
          "Bash(netcat -l -:*)"
          "Bash(rm -rf ~:*)"
          "Bash(rm -rf $HOME:*)"
          "Bash(rm -rf ~/.ssh*)"
          "Bash(rm -rf ~/.config*)"
        ];
      };
      hooks = {
        PreToolUse =
          lib.optionals pkgs.stdenv.isDarwin [
            {
              matcher = "Read";
              hooks = [
                {
                  type = "command";
                  command = "${claudeDotfilesDir}/hooks/obsidian-backlinks.zsh";
                }
              ];
            }
          ]
          ++ [
            {
              matcher = "Bash";
              hooks = [
                {
                  type = "command";
                  command = rtkHookPath;
                  timeout = 10;
                }
              ];
            }
          ];
        Stop = [
          {
            hooks = [
              {
                type = "command";
                command = "${claudeDotfilesDir}/hooks/notify.zsh";
              }
            ];
          }
        ];
        PermissionRequest = [
          {
            hooks = [
              {
                type = "command";
                command = "${claudeDotfilesDir}/hooks/notify.zsh";
              }
            ];
          }
        ];
        Notification = lib.optionals pkgs.stdenv.isDarwin [
          {
            hooks = [
              {
                type = "command";
                command = "${jq} -r '.message' | xargs -I {} ${terminal-notifier} -message \"{}\" -title \"Claude Code\" -group \"$(pwd):hook\" -activate com.mitchellh.ghostty";
              }
            ];
          }
        ];
        WorktreeCreate = [
          {
            hooks = [
              {
                type = "command";
                command = "${claudeDotfilesDir}/hooks/worktree.zsh";
              }
            ];
          }
        ];
        WorktreeRemove = [
          {
