      commit.verbose = true;
      rebase = {
        autoStash = true;
        autoSquash = true;
        updateRefs = true;
      };
      merge = {
        ff = false;
        conflictstyle = "zdiff3";
      };
      fetch = {
        writeCommitGraph = true;
        prune = true;
        pruneTags = true;
        all = true;
      };
      pull.rebase = true;
      init.defaultBranch = "main";
      column.ui = "auto";
      branch.sort = "-committerdate";
      help.autocorrect = "prompt";
      rerere = {
        enabled = true;
        autoupdate = true;
      };
      wt.basedir = ".git/worktree";
      wt.remover = "trash";
    };
  };
}

